C++<pre><code>类名&lt;类型实际参数表&gt;  对象名；
</code></pre> C++<pre><code>#include &lt;iostream&gt;
using namespace std;
template &lt;class T&gt;  // template&lt;typename T&gt;
class Max           // 声明类模板Max
{
private:
T item1, item2, item3;  // 类型为T,T在该类的对象生成时具体化
public:
Max() {}
Max(T thefirst, T thesecond, T thethird);
T GetMaxItem();  // 求得3个元素中的最大值并按类型T返回
void SetItem(T thefirst, T thesecond, T thethird);  // 设置类中的3个元素的值
};
// 类模板的实现
template &lt;class T&gt;
Max&lt;T&gt;::Max(T thefirst, T thesecond, T thethird)
: item1(thefirst), item2(thesecond), item3(thethird) {
return;
}
template &lt;class T&gt;
void Max&lt;T&gt;::SetItem(T thefirst, T thesecond, T thethird) {
item1 = thefirst;
item2 = thesecond;
item3 = thethird;
}
template &lt;class T&gt;
T Max&lt;T&gt;::GetMaxItem() {
T maxitem;
maxitem = item1 &gt; item2 ? item1 : item2;
maxitem = maxitem &gt; item3 ? maxitem : item3;
return maxitem;
}
// 主程序
int main() {
Max&lt;int&gt; nmyMax(1, 2, 3);
Max&lt;double&gt; dblmyMax(1.2, 1.3, -1.4);
cout &lt;&lt; nmyMax.GetMaxItem() &lt;&lt; endl;
cout &lt;&lt; dblmyMax.GetMaxItem() &lt;&lt; endl;
return 0;
}
</code></pre>

格式标志 作用 ios::left 输出数据在本域宽范围内向左对齐 ios::right 输出数据在本域宽范围内向右对齐 ios::internal 数值的符号位在域宽内左对齐，数值右对齐，中间由填充字符填充 ios::dec 设置整数的基数为10 ios::oct 设置整数的基数为8 ios::hex 设置整数的基数为16 ios::showbase 强制输出整数的基数(八进制数以0打头，十六进制数以0x打头) ios::showpoint 强制输出浮点数的小点和尾数0 ios::uppercase 在以科学记数法格式E和以十六进制输出字母时以大写表示 ios::showpos 对正数显示“+”号 ios::scientific 浮点数以科学记数法格式输出 ios::fixed 浮点数以定点格式(小数形式)输出 ios::unitbuf 每次输出之后刷新所有的流 ios::stdio 每次输出之后清除stdout, stderr <p>说明</p> <ul> <li><code>cout.width(n)</code>与格式控制符<code>setw(n)</code>相似</li> <li><code>cout.fill(c)</code>与格式控制符<code>setfill(c)</code>相似</li> </ul> C++<pre><code>#include &lt;iostream&gt;
using namespace std;
int main() {
int a = 21;
cout.setf(ios::showbase);
cout &lt;&lt; "dec:" &lt;&lt; a &lt;&lt; endl;
cout.unsetf(ios::dec);
cout.setf(ios::hex);
cout &lt;&lt; "hex:" &lt;&lt; a &lt;&lt; endl;
cout.unsetf(ios::hex);
cout.setf(ios::oct);
cout &lt;&lt; "oct:" &lt;&lt; a &lt;&lt; endl;
char *pt = "China";
cout.width(10);
cout &lt;&lt; pt &lt;&lt; endl;
cout.width(10);
cout.fill('*');
cout &lt;&lt; pt &lt;&lt; endl;
double pi = 22.0 / 7.0;
cout.setf(ios::scientific);
cout &lt;&lt; "pi=";
cout.width(14);
cout &lt;&lt; pi &lt;&lt; endl;
cout.unsetf(ios::scientific);
cout.setf(ios::fixed);
cout.width(12);
cout.setf(ios::showpos);
cout.setf(ios::internal);
cout.precision(6);
cout &lt;&lt; pi &lt;&lt; endl;
return 0;
}
</code></pre>

